const DEFAULT_SILVER_PURITIES = ["Silver 999", "Silver 925", "Silver 800"];

function getPurities(db, metalType) {
  const stored = db?.purities;
  if (stored && stored[metalType]) return stored[metalType];
  return metalType === "Gold" ? DEFAULT_GOLD_PURITIES : DEFAULT_SILVER_PURITIES;
}
function getAllPurities(db) {
  return [...getPurities(db,"Gold"), ...getPurities(db,"Silver")];
}

