// ── Shared date-range filter component ──────────────────────────────────
function DateRangeFilter({ from, to, onChange, style }) {
  const now = new Date(); const m = now.getMonth(); const y = now.getFullYear();
  const fyStart = m >= 3 ? y : y - 1;
  const presets = [
    { label:"This FY",    from:`${fyStart}-04-01`,   to:`${fyStart+1}-03-31` },
    { label:"Last FY",    from:`${fyStart-1}-04-01`, to:`${fyStart}-03-31` },
    { label:"This Month", from: new Date(y, m, 1).toISOString().split("T")[0],
                          to:   new Date(y, m+1, 0).toISOString().split("T")[0] },
    { label:"Last 3M",    from: new Date(Date.now()-90*24*60*60*1000).toISOString().split("T")[0],
                          to:   new Date().toISOString().split("T")[0] },
    { label:"All Time",   from:"", to:"" },
  ];
  const isActive = (p) => p.from===from && p.to===to;
  return (
    <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap", padding:"8px 12px",
      background:"var(--dark2)", border:"1px solid var(--dark4)", borderRadius:"3px", marginBottom:"14px", ...style }}>
      <span style={{ fontSize:"10px", color:"var(--gold-dim)", letterSpacing:"1px", whiteSpace:"nowrap" }}>DATE RANGE:</span>
      <input type="date" value={from} onChange={e=>onChange(e.target.value, to)}
        style={{ fontSize:"11px", padding:"3px 6px", background:"var(--dark3)", border:"1px solid var(--dark4)",
          color:"var(--gold-light)", borderRadius:"2px", colorScheme:"dark" }} />
      <span style={{ color:"var(--gold-dim)", fontSize:"11px" }}>to</span>
      <input type="date" value={to} onChange={e=>onChange(from, e.target.value)}
        style={{ fontSize:"11px", padding:"3px 6px", background:"var(--dark3)", border:"1px solid var(--dark4)",
          color:"var(--gold-light)", borderRadius:"2px", colorScheme:"dark" }} />
      <div style={{ display:"flex", gap:"4px", marginLeft:"4px", flexWrap:"wrap" }}>
        {presets.map(p=>(
          <button key={p.label} onClick={()=>onChange(p.from, p.to)} style={{
            padding:"3px 8px", fontSize:"10px", cursor:"pointer", borderRadius:"2px",
            border:"1px solid", letterSpacing:"0.5px",
            borderColor: isActive(p) ? "var(--gold)" : "var(--dark4)",
            background:  isActive(p) ? "var(--gold)" : "var(--dark3)",
            color:       isActive(p) ? "#0a0a0f"    : "var(--gold-dim)",
          }}>{p.label}</button>
        ))}
      </div>
    </div>
  );
}
function useDateRange() {
  const getFYDates = () => {
    const n = new Date(); const m = n.getMonth(); const y = n.getFullYear();
    const s = m >= 3 ? y : y - 1;
    return { from:`${s}-04-01`, to:`${s+1}-03-31` };
  };
  const [dr, setDr] = React.useState(getFYDates);
  const inRange = (dateStr) => {
    if(!dr.from && !dr.to) return true;
    if(!dateStr) return true;
    try {
      const d = new Date(dateStr).toISOString().split("T")[0];
      if(dr.from && d < dr.from) return false;
      if(dr.to   && d > dr.to)   return false;
      return true;
    } catch { return true; }
  };
  return { from:dr.from, to:dr.to, inRange, setRange:(f,t)=>setDr({from:f,to:t}) };
}

