function generateOrderNo(orders) {
  const now = new Date();
  const month = now.getMonth();
  const year = now.getFullYear();
  const fyStart = month >= 3 ? year : year - 1;
  const fyKey = `${String(fyStart).slice(2)}${String(fyStart+1).slice(2)}`;
  const existing = (orders||[]).filter(o=>o.orderNo&&o.orderNo.startsWith(`ORD-${fyKey}`));
  const next = existing.length + 1;
  return `ORD-${fyKey}-${String(next).padStart(4,"0")}`;
}

function nextBagNo(counters, metalType, categoryCode) {
  const prefix = metalType === "Gold" ? "BGG" : "BGS";
  const key = `${prefix}-${categoryCode}`;
  const next = (counters[key] || 0) + 1;
  return { bagNo: `${key}${next}`, key, next };
}

