// ============================================================
// SCHEMA MIGRATION — runs on every load, safe (only adds fields)
// ============================================================
const CURRENT_SCHEMA_VERSION = 2;

function migrateDB(db) {
  const v = db.schemaVersion || 1;
  if (v >= CURRENT_SCHEMA_VERSION) return db; // already up to date

  let migrated = { ...db };
  const logs = [];

  // ── v1 → v2: add alerts, messages, schemaVersion ─────────────
  if (v < 2) {
    if (!migrated.alerts)   migrated.alerts   = [];
    if (!migrated.messages) migrated.messages = [];
    // Ensure all bags have required fields
    migrated.bags = (migrated.bags||[]).map(b => ({
      pendingIssue:     false,
      isBroken:         false,
      hasStones:        false,
      stoneWeightGrams: 0,
      pmBookDeliveredToCO: false,
      needsMetalFlag:   false,
      needsStonesFlag:  false,
      ...b,
    }));
    // Ensure all transactions have required fields
    migrated.transactions = (migrated.transactions||[]).map(t => ({
      recoveryWeight: 0,
      lossWeight:     null,
      groupLabel:     null,
      ...t,
    }));
    // Ensure all karigars have required fields
    migrated.karigars = (migrated.karigars||[]).map(k => ({
      isActive: true,
      phone:    "",
      ...k,
    }));
    // Ensure all coReceipts have required fields
    if(!migrated.readyStock) migrated.readyStock = [];
    migrated.coReceipts = (migrated.coReceipts||[]).map(r => ({
      invoiceStatus:  "Pending",
      deliveryStatus: "Pending",
      ledgerRecorded: false,
      photo:          null,
      ...r,
    }));
    migrated.schemaVersion = 2;
    logs.push(`Schema migrated v1→v2: alerts, messages, bag flags, receipt photos`);
  }

  // Write migration logs to auditLogs
  if (logs.length > 0) {
    migrated.auditLogs = [
      ...(migrated.auditLogs||[]),
      ...logs.map(msg => ({ id: generateId(), action:"SCHEMA_MIGRATION",
        entityId:"db", details:msg, timestamp:new Date().toISOString() }))
    ];
  }

  return migrated;
}

