function AccountsView({ db, updateDB, user }) {
  const [acTab, setAcTab] = useState("dashboard");

  // ── Sub-tab navigation ──────────────────────────────────────────────
  const tabs = [
    { id:"dashboard",  label:"📊 Overview" },
    { id:"parties",    label:"👥 Parties" },
    { id:"stock",      label:"📦 Stock Register" },
    { id:"repair",     label:"🔧 Repair Jobs" },
    { id:"approval",   label:"⏳ Approval Stock" },
    { id:"ledger",     label:"📒 Party Ledger" },
    { id:"outstanding",label:"💰 Outstanding" },
  ];

  return (
    <div>
      <div style={{ fontSize:"10px", color:"var(--text-secondary)", letterSpacing:"4px", fontWeight:"bold", textTransform:"uppercase", paddingBottom:"12px", borderBottom:"1px solid var(--dark4)", marginBottom:"20px" }}>📒 ACCOUNTS</div>
      <div className="tab-bar" style={{ flexWrap:"wrap" }}>
        {tabs.map(t=>(
          <button key={t.id} className={`btn ${acTab===t.id?"btn-gold":""}`} onClick={()=>setAcTab(t.id)} style={{ fontSize:"11px" }}>{t.label}</button>
        ))}
      </div>

      {acTab==="dashboard"   && <AccountsDashboard db={db} />}
      {acTab==="parties"     && <PartiesView db={db} updateDB={updateDB} />}
      {acTab==="stock"       && <StockRegisterView db={db} updateDB={updateDB} />}
      {acTab==="repair"      && <RepairJobsView db={db} updateDB={updateDB} />}
      {acTab==="approval"    && <ApprovalStockView db={db} updateDB={updateDB} />}
      {acTab==="ledger"      && <PartyLedgerView db={db} updateDB={updateDB} />}
      {acTab==="outstanding" && <OutstandingView db={db} />}
    </div>
  );
}

// ── Dashboard ──────────────────────────────────────────────────────────
function AccountsDashboard({ db }) {
  const parties   = db.parties||[];
  const ftxns     = db.financialTxns||[];
  const approvals = db.approvalStock||[];
  const repairs   = db.repairJobs||[];

  // Outstanding receivables (customers owe us)
  const totalReceivable = parties.filter(p=>p.type==="customer").reduce((s,p)=>{
    const bal = partyBalance(p.id, ftxns);
    return s + Math.max(0, bal);
  }, 0);

  // Outstanding payables (we owe suppliers)
  const totalPayable = parties.filter(p=>p.type==="supplier").reduce((s,p)=>{
    const bal = partyBalance(p.id, ftxns);
    return s + Math.max(0, -bal);
  }, 0);

  const pendingApprovals = approvals.filter(a=>a.status==="pending");
  const approvalValue = pendingApprovals.reduce((s,a)=>s+(a.totalValue||0),0);
  const openRepairs = repairs.filter(r=>r.status!=="delivered").length;

  // Recent transactions
  const recent = [...ftxns].sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,8);

  return (
    <div>
      <div className="mini-stats" style={{ marginBottom:"22px" }}>
        {[
          { label:"Total Receivable", value:`₹${totalReceivable.toLocaleString("en-IN",{maximumFractionDigits:0})}`, sub:"customers owe us", color:"var(--recovery)", accent:"var(--recovery)" },
          { label:"Total Payable",    value:`₹${totalPayable.toLocaleString("en-IN",{maximumFractionDigits:0})}`,    sub:"we owe suppliers", color:"var(--loss)",     accent:"var(--loss)" },
          { label:"Approval Stock",   value:`₹${approvalValue.toLocaleString("en-IN",{maximumFractionDigits:0})}`,   sub:`${pendingApprovals.length} pending`,  color:"var(--warning)", accent:"var(--warning)" },
          { label:"Open Repairs",     value:openRepairs,  sub:"jobs in progress", color:"var(--info)", accent:"var(--info)" },
        ].map((c,i)=>(
          <div key={i} className="mini-stat" style={{ borderTop:`2px solid ${c.accent}` }}>
            <div className="mini-stat-label">{c.label}</div>
            <div className="mini-stat-value" style={{ color:c.color }}>{c.value}</div>
            <div className="mini-stat-sub">{c.sub}</div>
          </div>
        ))}
      </div>

      <div className="card card-gold">
        <div className="section-title"><span className="section-title-accent"></span>Recent Financial Transactions</div>
        {recent.length===0 && <div style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No transactions yet. Add parties and start recording.</div>}
        {recent.length>0 && (
          <table>
            <thead><tr><th>Date</th><th>Type</th><th>Party</th><th>Description</th><th>Qty</th><th>Amount</th><th>Mode</th><th>Notes</th></tr></thead>
            <tbody>
              {recent.map(t=>{
                const party = (db.parties||[]).find(p=>p.id===t.partyId);
                const isCredit = ["sale","receipt"].includes(t.txType||"");
                const txType = t.txType||"";
                return (
                  <tr key={t.id}>
                    <td style={{ fontSize:"10px", color:"var(--gold-dim)", whiteSpace:"nowrap" }}>{t.date ? new Date(t.date).toLocaleDateString("en-IN") : "—"}</td>
                    <td><span className={`badge ${txType==="sale"?"badge-green":txType==="purchase"?"badge-red":txType==="receipt"?"badge-gold":txType==="payment"?"badge-orange":"badge-blue"}`} style={{ fontSize:"10px" }}>{txType.toUpperCase()||"—"}</span></td>
                    <td style={{ color:"var(--gold)", fontSize:"12px" }}>{party?.name||"—"}</td>
                    <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{t.description||"—"}</td>
                    <td style={{ fontSize:"11px" }}>{t.quantity!=null?`${t.quantity} ${t.unit||""}`:""}</td>
                    <td style={{ fontWeight:"bold", color:isCredit?"#4db88a":"#d46060" }}>{isCredit?"+":"-"}₹{(t.amount||0).toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                    <td><span className={`badge ${t.payMode==="cash"?"badge-green":"badge-orange"}`} style={{ fontSize:"10px" }}>{t.payMode||"credit"}</span></td>
                    <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{t.notes||""}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

// ── Party balance helper ────────────────────────────────────────────────
function partyBalance(partyId, ftxns) {
  // Positive = party owes us (debtor). Negative = we owe party (creditor).
  return (ftxns||[]).filter(t=>t.partyId===partyId).reduce((s,t)=>{
    if(t.txType==="sale")     return s + (t.amount||0);
    if(t.txType==="purchase") return s - (t.amount||0);
    if(t.txType==="receipt")  return s - (t.amount||0); // received cash from customer reduces balance
    if(t.txType==="payment")  return s + (t.amount||0); // paid cash to supplier reduces balance
    if(t.txType==="debit_note")  return s + (t.amount||0);
    if(t.txType==="credit_note") return s - (t.amount||0);
    return s;
  }, 0);
}

// ── Parties ────────────────────────────────────────────────────────────
function PartiesView({ db, updateDB }) {
  const [showForm, setShowForm] = useState(false);
  const [filterType, setFilterType] = useState("all");
  const [form, setForm] = useState({ name:"", type:"customer", phone:"", address:"", gstin:"", notes:"" });

  const handleAdd = () => {
    if(!form.name.trim()) return alert("Party name is required");
    updateDB(prev=>{
      if(!prev.parties) prev.parties=[];
      prev.parties.push({ id:generateId(), ...form, createdAt:now(), isActive:true });
      prev.auditLogs.push({ id:generateId(), action:"PARTY_ADDED", entityId:form.name, details:`${form.type}: ${form.name}`, timestamp:now() });
      return prev;
    });
    setForm({ name:"", type:"customer", phone:"", address:"", gstin:"", notes:"" });
    setShowForm(false);
  };

  const toggleActive = (id) => {
    updateDB(prev=>{ const p=prev.parties.find(x=>x.id===id); if(p) p.isActive=!p.isActive; return prev; });
  };

  const parties = (db.parties||[]).filter(p=>filterType==="all"||p.type===filterType);

  return (
    <div>
      <div style={{ display:"flex", gap:"8px", marginBottom:"14px", alignItems:"center" }}>
        {[["all","All"],["customer","Customers"],["supplier","Suppliers"]].map(([v,l])=>(
          <button key={v} className={`btn ${filterType===v?"btn-gold":""}`} onClick={()=>setFilterType(v)}>{l}</button>
        ))}
        <button className="btn btn-gold" style={{ marginLeft:"auto" }} onClick={()=>setShowForm(!showForm)}>+ Add Party</button>
      </div>

      {showForm && (
        <div className="card card-gold fade-in" style={{ marginBottom:"14px" }}>
          <div className="modal-title">New Party</div>
          <div className="form-grid">
            <div className="form-group"><div className="label">Type</div>
              <select value={form.type} onChange={e=>setForm({...form,type:e.target.value})}>
                <option value="customer">Customer (Debtor)</option>
                <option value="supplier">Supplier / Vendor (Creditor)</option>
              </select>
            </div>
            <div className="form-group"><div className="label">Name *</div>
              <input value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="Full name or company" />
            </div>
            <div className="form-group"><div className="label">Phone</div>
              <input value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">GSTIN (optional)</div>
              <input value={form.gstin} onChange={e=>setForm({...form,gstin:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Address</div>
              <input value={form.address} onChange={e=>setForm({...form,address:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Notes</div>
              <input value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} />
            </div>
          </div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button className="btn btn-gold" onClick={handleAdd}>✓ Save Party</button>
            <button className="btn" onClick={()=>setShowForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      <div className="card card-gold">
        <table>
          <thead><tr><th>Type</th><th>Name</th><th>Phone</th><th>GSTIN</th><th>Balance</th><th>Status</th><th></th></tr></thead>
          <tbody>
            {parties.map(p=>{
              const bal = partyBalance(p.id, db.financialTxns||[]);
              const isDebtor = bal > 0;
              return (
                <tr key={p.id} style={{ opacity:p.isActive?1:0.5 }}>
                  <td><span className={`badge ${p.type==="customer"?"badge-blue":"badge-orange"}`}>{p.type==="customer"?"Customer":"Supplier"}</span></td>
                  <td style={{ color:"var(--gold)", fontWeight:"bold" }}>{p.name}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{p.phone||"—"}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{p.gstin||"—"}</td>
                  <td style={{ fontWeight:"bold", color: bal===0?"var(--gold-dim)":isDebtor?"#4db88a":"#d46060" }}>
                    {bal===0?"—":`${isDebtor?"They owe: ":"We owe: "}₹${Math.abs(bal).toLocaleString("en-IN",{maximumFractionDigits:0})}`}
                  </td>
                  <td><span className={`badge ${p.isActive?"badge-green":"badge-red"}`}>{p.isActive?"Active":"Inactive"}</span></td>
                  <td><button className="btn btn-sm" onClick={()=>toggleActive(p.id)}>{p.isActive?"Deactivate":"Activate"}</button></td>
                </tr>
              );
            })}
            {parties.length===0 && <tr><td colSpan={7} style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No parties yet. Add customers and suppliers to get started.</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Stock Register ──────────────────────────────────────────────────────
function StockRegisterView({ db, updateDB }) {
  const [showForm, setShowForm] = useState(false);
  const [filterCat, setFilterCat] = useState("all");
  const [form, setForm] = useState({
    txType:"purchase", category:"pure_metal", description:"", party:"", partyId:"",
    quantity:"", unit:"g", ratePerUnit:"", totalValue:"", payMode:"credit",
    gemstoneOwnership:"market", date:"", notes:""
  });

  const CATEGORIES = [
    { id:"pure_metal", label:"Pure Metal" },
    { id:"alloy",      label:"Alloy" },
    { id:"gemstone",   label:"Gemstone / Diamond" },
    { id:"jewellery",  label:"Finished Jewellery" },
  ];

  const handleAdd = () => {
    if(!form.description.trim()) return alert("Description is required");
    if(!form.quantity||parseFloat(form.quantity)<=0) return alert("Enter quantity");
    const qty   = parseFloat(form.quantity)||0;
    const rate  = parseFloat(form.ratePerUnit)||0;
    const total = form.totalValue ? parseFloat(form.totalValue) : qty*rate;
    const entry = {
      id:generateId(), txType:form.txType, category:form.category,
      description:form.description, partyId:form.partyId, partyName:form.party,
      quantity:qty, unit:form.unit, ratePerUnit:rate, totalValue:total,
      payMode:form.payMode, gemstoneOwnership:form.category==="gemstone"?form.gemstoneOwnership:null,
      date:form.date||now(), notes:form.notes,
    };
    updateDB(prev=>{
      if(!prev.stockTransactions) prev.stockTransactions=[];
      prev.stockTransactions.push(entry);
      // If credit transaction — create financial entry too
      if(form.partyId && total>0) {
        if(!prev.financialTxns) prev.financialTxns=[];
        prev.financialTxns.push({
          id:generateId(), partyId:form.partyId,
          txType: form.txType==="purchase"?"purchase":"sale",
          description:form.description, quantity:qty, unit:form.unit,
          amount:total, payMode:form.payMode,
          date:form.date||now(), notes:form.notes, linkedStockId:entry.id,
        });
      }
      prev.auditLogs.push({ id:generateId(), action:"STOCK_TXN", entityId:entry.id, details:`${form.txType} — ${form.description} ${qty}${form.unit} @ ₹${rate}`, timestamp:now() });
      return prev;
    });
    setForm({ txType:"purchase", category:"pure_metal", description:"", party:"", partyId:"", quantity:"", unit:"g", ratePerUnit:"", totalValue:"", payMode:"credit", gemstoneOwnership:"market", date:"", notes:"" });
    setShowForm(false);
  };

  const txns = (db.stockTransactions||[]).filter(t=>filterCat==="all"||t.category===filterCat);

  // Stock summary per category
  const summary = {};
  (db.stockTransactions||[]).forEach(t=>{
    const k = t.category+(t.unit||"g");
    if(!summary[k]) summary[k]={ category:t.category, unit:t.unit||"g", in:0, out:0, value:0 };
    if(["purchase","receipt"].includes(t.txType))  { summary[k].in  += t.quantity||0; summary[k].value += t.totalValue||0; }
    if(["sale","issue"].includes(t.txType))        { summary[k].out += t.quantity||0; summary[k].value -= t.totalValue||0; }
  });

  return (
    <div>
      <div style={{ display:"flex", gap:"8px", marginBottom:"14px", alignItems:"center", flexWrap:"wrap" }}>
        {[["all","All"],["pure_metal","Pure Metal"],["alloy","Alloy"],["gemstone","Gemstones"],["jewellery","Jewellery"]].map(([v,l])=>(
          <button key={v} className={`btn ${filterCat===v?"btn-gold":""}`} onClick={()=>setFilterCat(v)}>{l}</button>
        ))}
        <button className="btn btn-gold" style={{ marginLeft:"auto" }} onClick={()=>setShowForm(!showForm)}>+ New Entry</button>
      </div>

      {/* Summary cards */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))", gap:"10px", marginBottom:"16px" }}>
        {Object.values(summary).map((s,i)=>(
          <div key={i} style={{ background:"var(--dark3)", border:"1px solid var(--dark4)", borderRadius:"3px", padding:"10px 14px" }}>
            <div style={{ fontSize:"10px", color:"var(--gold-dim)", letterSpacing:"1px", marginBottom:"6px" }}>{CATEGORIES.find(c=>c.id===s.category)?.label||s.category}</div>
            <div style={{ fontSize:"16px", fontWeight:"bold", color:"var(--gold)", fontFamily:"monospace" }}>{(s.in-s.out).toFixed(3)} {s.unit}</div>
            <div style={{ fontSize:"10px", color:"var(--gold-dim)", marginTop:"4px" }}>In: {s.in.toFixed(3)} | Out: {s.out.toFixed(3)}</div>
          </div>
        ))}
      </div>

      {showForm && (
        <div className="card card-gold fade-in" style={{ marginBottom:"14px" }}>
          <div className="modal-title">New Stock Entry</div>
          <div className="form-grid">
            <div className="form-group"><div className="label">Transaction Type</div>
              <select value={form.txType} onChange={e=>setForm({...form,txType:e.target.value})}>
                <option value="purchase">Purchase (Incoming)</option>
                <option value="sale">Sale (Outgoing)</option>
                <option value="receipt">Receipt (Return / Other In)</option>
                <option value="issue">Issue / Consumption</option>
              </select>
            </div>
            <div className="form-group"><div className="label">Category</div>
              <select value={form.category} onChange={e=>setForm({...form,category:e.target.value})}>
                {CATEGORIES.map(c=><option key={c.id} value={c.id}>{c.label}</option>)}
              </select>
            </div>
            {form.category==="gemstone" && (
              <div className="form-group"><div className="label">Gemstone Source</div>
                <select value={form.gemstoneOwnership} onChange={e=>setForm({...form,gemstoneOwnership:e.target.value})}>
                  <option value="market">Market Purchase</option>
                  <option value="customer_own">Customer's Own Stones (tagged to customer)</option>
                  <option value="customer_general">Customer's Stones (into general stock)</option>
                </select>
              </div>
            )}
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Description *</div>
              <input value={form.description} onChange={e=>setForm({...form,description:e.target.value})} placeholder="e.g. 22K Gold Bar, Diamond 0.5ct VS1, Platinum Ring, etc." />
            </div>
            <div className="form-group"><div className="label">Quantity *</div>
              <input type="number" step="0.001" value={form.quantity} onChange={e=>setForm({...form,quantity:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Unit</div>
              <select value={form.unit} onChange={e=>setForm({...form,unit:e.target.value})}>
                <option value="g">Grams (g)</option>
                <option value="ct">Carats (ct)</option>
                <option value="pcs">Pieces</option>
                <option value="kg">Kilograms (kg)</option>
              </select>
            </div>
            <div className="form-group"><div className="label">Rate per Unit (₹)</div>
              <input type="number" step="1" value={form.ratePerUnit} onChange={e=>setForm({...form,ratePerUnit:e.target.value,totalValue:""})} />
            </div>
            <div className="form-group"><div className="label">Total Value (₹)</div>
              <input type="number" step="1" value={form.totalValue||(form.ratePerUnit&&form.quantity?(parseFloat(form.ratePerUnit)*parseFloat(form.quantity)).toFixed(0):"")} onChange={e=>setForm({...form,totalValue:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Party / Supplier / Customer</div>
              <select value={form.partyId} onChange={e=>{ const p=(db.parties||[]).find(x=>x.id===e.target.value); setForm({...form,partyId:e.target.value,party:p?.name||""}); }}>
                <option value="">— Select Party —</option>
                {(db.parties||[]).filter(p=>p.isActive).map(p=><option key={p.id} value={p.id}>{p.name} ({p.type})</option>)}
              </select>
            </div>
            <div className="form-group"><div className="label">Payment Mode</div>
              <select value={form.payMode} onChange={e=>setForm({...form,payMode:e.target.value})}>
                <option value="credit">Credit</option>
                <option value="cash">Cash</option>
                <option value="bank">Bank Transfer</option>
              </select>
            </div>
            <div className="form-group"><div className="label">Date</div>
              <input type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Notes</div>
              <input value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} />
            </div>
          </div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button className="btn btn-gold" onClick={handleAdd}>✓ Save Entry</button>
            <button className="btn" onClick={()=>setShowForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      <div className="card card-gold">
        <table>
          <thead><tr><th>Date</th><th>Type</th><th>Category</th><th>Description</th><th>Qty</th><th>Rate</th><th>Value</th><th>Party</th><th>Mode</th></tr></thead>
          <tbody>
            {[...txns].reverse().map(t=>{
              const party = (db.parties||[]).find(p=>p.id===t.partyId);
              return (
                <tr key={t.id}>
                  <td style={{ fontSize:"10px", color:"var(--gold-dim)", whiteSpace:"nowrap" }}>{new Date(t.date).toLocaleDateString("en-IN")}</td>
                  <td><span className={`badge ${t.txType==="purchase"?"badge-red":t.txType==="sale"?"badge-green":"badge-blue"}`} style={{ fontSize:"10px" }}>{t.txType.toUpperCase()}</span></td>
                  <td style={{ fontSize:"11px" }}>{CATEGORIES.find(c=>c.id===t.category)?.label||t.category}</td>
                  <td style={{ fontSize:"12px", color:"var(--gold-dim)" }}>{t.description}</td>
                  <td style={{ fontSize:"12px" }}>{t.quantity} {t.unit}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{t.ratePerUnit?`₹${t.ratePerUnit.toLocaleString("en-IN")}`:"—"}</td>
                  <td style={{ fontWeight:"bold", color:["purchase","receipt"].includes(t.txType)?"#d46060":"#4db88a" }}>₹{(t.totalValue||0).toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold)" }}>{party?.name||t.partyName||"—"}</td>
                  <td><span className={`badge ${t.payMode==="cash"?"badge-green":t.payMode==="bank"?"badge-blue":"badge-orange"}`} style={{ fontSize:"9px" }}>{t.payMode||"credit"}</span></td>
                </tr>
              );
            })}
            {txns.length===0 && <tr><td colSpan={9} style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No entries yet</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Repair Jobs ────────────────────────────────────────────────────────
function RepairJobsView({ db, updateDB }) {
  const [showForm, setShowForm] = useState(false);
  const [filterStatus, setFilterStatus] = useState("all");
  const [form, setForm] = useState({
    customerId:"", description:"", itemWeight:"", metalType:"Gold",
    stonesDescription:"", estimatedCharge:"", receivedDate:"", expectedDate:"", notes:""
  });
  const [selectedJob, setSelectedJob] = useState(null);
  const [deliverForm, setDeliverForm] = useState({ actualCharge:"", metalAdded:"", stonesAdded:"", notes:"", deliveryDate:"" });

  const handleAdd = () => {
    if(!form.customerId) return alert("Select a customer");
    if(!form.description.trim()) return alert("Enter item description");
    updateDB(prev=>{
      if(!prev.repairJobs) prev.repairJobs=[];
      const job = {
        id:generateId(), jobNo:"RPR-"+String((prev.repairJobs.length||0)+1).padStart(4,"0"),
        customerId:form.customerId, customerName:(prev.parties||[]).find(p=>p.id===form.customerId)?.name||"",
        description:form.description, itemWeight:parseFloat(form.itemWeight)||0,
        metalType:form.metalType, stonesDescription:form.stonesDescription,
        estimatedCharge:parseFloat(form.estimatedCharge)||0,
        receivedDate:form.receivedDate||now(), expectedDate:form.expectedDate||"",
        status:"received", notes:form.notes, createdAt:now(),
      };
      prev.repairJobs.push(job);
      prev.auditLogs.push({ id:generateId(), action:"REPAIR_RECEIVED", entityId:job.jobNo, details:`Repair: ${form.description} from ${job.customerName}`, timestamp:now() });
      return prev;
    });
    setForm({ customerId:"", description:"", itemWeight:"", metalType:"Gold", stonesDescription:"", estimatedCharge:"", receivedDate:"", expectedDate:"", notes:"" });
    setShowForm(false);
  };

  const handleDeliver = () => {
    if(!selectedJob) return;
    const charge = parseFloat(deliverForm.actualCharge)||0;
    updateDB(prev=>{
      const job = prev.repairJobs.find(j=>j.id===selectedJob);
      if(!job) return prev;
      job.status = "delivered";
      job.actualCharge = charge;
      job.metalAdded = deliverForm.metalAdded;
      job.stonesAdded = deliverForm.stonesAdded;
      job.deliveryDate = deliverForm.deliveryDate||now();
      job.deliveryNotes = deliverForm.notes;
      // Create financial entry for the repair charge
      if(charge>0 && job.customerId){
        if(!prev.financialTxns) prev.financialTxns=[];
        prev.financialTxns.push({
          id:generateId(), partyId:job.customerId,
          txType:"sale", description:`Repair charges — ${job.description} (${job.jobNo})`,
          quantity:1, unit:"job", amount:charge, payMode:"credit",
          date:deliverForm.deliveryDate||now(), notes:deliverForm.notes,
        });
      }
      prev.auditLogs.push({ id:generateId(), action:"REPAIR_DELIVERED", entityId:job.jobNo, details:`Repair delivered: ${job.description} — ₹${charge}`, timestamp:now() });
      return prev;
    });
    setSelectedJob(null);
    setDeliverForm({ actualCharge:"", metalAdded:"", stonesAdded:"", notes:"", deliveryDate:"" });
  };

  const jobs = (db.repairJobs||[]).filter(j=>filterStatus==="all"||j.status===filterStatus);

  return (
    <div>
      <div style={{ display:"flex", gap:"8px", marginBottom:"14px", alignItems:"center" }}>
        {[["all","All"],["received","Received"],["in_progress","In Progress"],["delivered","Delivered"]].map(([v,l])=>(
          <button key={v} className={`btn ${filterStatus===v?"btn-gold":""}`} onClick={()=>setFilterStatus(v)}>{l}</button>
        ))}
        <button className="btn btn-gold" style={{ marginLeft:"auto" }} onClick={()=>setShowForm(!showForm)}>+ Receive Repair</button>
      </div>

      {showForm && (
        <div className="card card-gold fade-in" style={{ marginBottom:"14px" }}>
          <div className="modal-title">Receive Jewellery for Repair</div>
          <div className="info-box" style={{ marginBottom:"12px" }}>⚠ Repair items are NOT added to your gold/silver stock. They are tracked separately.</div>
          <div className="form-grid">
            <div className="form-group"><div className="label">Customer *</div>
              <select value={form.customerId} onChange={e=>setForm({...form,customerId:e.target.value})}>
                <option value="">— Select Customer —</option>
                {(db.parties||[]).filter(p=>p.type==="customer"&&p.isActive).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="form-group"><div className="label">Metal Type</div>
              <select value={form.metalType} onChange={e=>setForm({...form,metalType:e.target.value})}>
                <option>Gold</option><option>Silver</option><option>Platinum</option><option>Other</option>
              </select>
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Item Description *</div>
              <input value={form.description} onChange={e=>setForm({...form,description:e.target.value})} placeholder="e.g. 22K Gold Necklace with diamonds, broken clasp" />
            </div>
            <div className="form-group"><div className="label">Item Weight (g)</div>
              <input type="number" step="0.001" value={form.itemWeight} onChange={e=>setForm({...form,itemWeight:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Estimated Charge (₹)</div>
              <input type="number" step="1" value={form.estimatedCharge} onChange={e=>setForm({...form,estimatedCharge:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Received Date</div>
              <input type="date" value={form.receivedDate} onChange={e=>setForm({...form,receivedDate:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Expected Return Date</div>
              <input type="date" value={form.expectedDate} onChange={e=>setForm({...form,expectedDate:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Stones / Diamonds Description</div>
              <input value={form.stonesDescription} onChange={e=>setForm({...form,stonesDescription:e.target.value})} placeholder="e.g. 3 diamonds approx 0.3ct each" />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Notes</div>
              <input value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} />
            </div>
          </div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button className="btn btn-gold" onClick={handleAdd}>✓ Receive Job</button>
            <button className="btn" onClick={()=>setShowForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      {selectedJob && (
        <div className="card card-gold fade-in" style={{ marginBottom:"14px", borderColor:"#4db88a" }}>
          <div className="modal-title" style={{ color:"#4db88a" }}>Deliver Repair Job</div>
          <div className="form-grid">
            <div className="form-group"><div className="label">Actual Charges (₹)</div>
              <input type="number" step="1" value={deliverForm.actualCharge} onChange={e=>setDeliverForm({...deliverForm,actualCharge:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Metal Added (if any, g)</div>
              <input value={deliverForm.metalAdded} onChange={e=>setDeliverForm({...deliverForm,metalAdded:e.target.value})} placeholder="e.g. 0.5g 22K gold for soldering" />
            </div>
            <div className="form-group"><div className="label">Stones Added (if any)</div>
              <input value={deliverForm.stonesAdded} onChange={e=>setDeliverForm({...deliverForm,stonesAdded:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Delivery Date</div>
              <input type="date" value={deliverForm.deliveryDate} onChange={e=>setDeliverForm({...deliverForm,deliveryDate:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Notes</div>
              <input value={deliverForm.notes} onChange={e=>setDeliverForm({...deliverForm,notes:e.target.value})} />
            </div>
          </div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button className="btn btn-gold" onClick={handleDeliver}>✓ Mark Delivered</button>
            <button className="btn" onClick={()=>setSelectedJob(null)}>Cancel</button>
          </div>
        </div>
      )}

      <div className="card card-gold">
        <table>
          <thead><tr><th>Job No</th><th>Customer</th><th>Description</th><th>Wt</th><th>Received</th><th>Expected</th><th>Est. Charge</th><th>Status</th><th></th></tr></thead>
          <tbody>
            {[...jobs].reverse().map(j=>(
              <tr key={j.id}>
                <td style={{ color:"var(--gold)", fontWeight:"bold" }}>{j.jobNo}</td>
                <td style={{ fontSize:"12px" }}>{j.customerName}</td>
                <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{j.description}</td>
                <td style={{ fontSize:"11px" }}>{j.itemWeight?j.itemWeight+"g":"—"}</td>
                <td style={{ fontSize:"10px", color:"var(--gold-dim)" }}>{j.receivedDate?new Date(j.receivedDate).toLocaleDateString("en-IN"):"—"}</td>
                <td style={{ fontSize:"10px", color: j.expectedDate&&new Date(j.expectedDate)<new Date()&&j.status!=="delivered"?"#d46060":"var(--gold-dim)" }}>{j.expectedDate?new Date(j.expectedDate).toLocaleDateString("en-IN"):"—"}</td>
                <td style={{ fontSize:"12px" }}>{j.estimatedCharge?`₹${j.estimatedCharge.toLocaleString("en-IN")}`:"—"}</td>
                <td><span className={`badge ${j.status==="delivered"?"badge-green":j.status==="in_progress"?"badge-blue":"badge-orange"}`}>{j.status}</span></td>
                <td>{j.status!=="delivered" && <button className="btn btn-sm btn-gold" onClick={()=>{ setSelectedJob(j.id); setDeliverForm({ actualCharge:j.estimatedCharge||"", metalAdded:"", stonesAdded:"", notes:"", deliveryDate:"" }); }}>Deliver</button>}</td>
              </tr>
            ))}
            {jobs.length===0 && <tr><td colSpan={9} style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No repair jobs yet</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Approval Stock ──────────────────────────────────────────────────────
function ApprovalStockView({ db, updateDB }) {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ partyId:"", description:"", category:"gemstone", quantity:"", unit:"ct", ratePerUnit:"", totalValue:"", receivedDate:"", notes:"" });

  const handleAdd = () => {
    if(!form.partyId) return alert("Select a supplier");
    if(!form.description.trim()) return alert("Enter description");
    const qty = parseFloat(form.quantity)||0;
    const rate = parseFloat(form.ratePerUnit)||0;
    const total = form.totalValue ? parseFloat(form.totalValue) : qty*rate;
    updateDB(prev=>{
      if(!prev.approvalStock) prev.approvalStock=[];
      prev.approvalStock.push({
        id:generateId(), partyId:form.partyId,
        partyName:(prev.parties||[]).find(p=>p.id===form.partyId)?.name||"",
        description:form.description, category:form.category,
        quantity:qty, unit:form.unit, ratePerUnit:rate, totalValue:total,
        receivedDate:form.receivedDate||now(), status:"pending", notes:form.notes, createdAt:now(),
      });
      prev.auditLogs.push({ id:generateId(), action:"APPROVAL_RECEIVED", entityId:form.description, details:`On approval: ${form.description} from ${(prev.parties||[]).find(p=>p.id===form.partyId)?.name||""}`, timestamp:now() });
      return prev;
    });
    setForm({ partyId:"", description:"", category:"gemstone", quantity:"", unit:"ct", ratePerUnit:"", totalValue:"", receivedDate:"", notes:"" });
    setShowForm(false);
  };

  const confirmPurchase = (id) => {
    updateDB(prev=>{
      const item = (prev.approvalStock||[]).find(a=>a.id===id);
      if(!item) return prev;
      item.status = "purchased";
      item.confirmedAt = now();
      // Create stock transaction
      if(!prev.stockTransactions) prev.stockTransactions=[];
      prev.stockTransactions.push({ id:generateId(), txType:"purchase", category:item.category, description:item.description, partyId:item.partyId, partyName:item.partyName, quantity:item.quantity, unit:item.unit, ratePerUnit:item.ratePerUnit, totalValue:item.totalValue, payMode:"credit", date:now(), notes:"Converted from approval — "+item.notes });
      // Create financial liability
      if(!prev.financialTxns) prev.financialTxns=[];
      prev.financialTxns.push({ id:generateId(), partyId:item.partyId, txType:"purchase", description:item.description, quantity:item.quantity, unit:item.unit, amount:item.totalValue, payMode:"credit", date:now(), notes:"From approval stock" });
      prev.auditLogs.push({ id:generateId(), action:"APPROVAL_PURCHASED", entityId:id, details:`Approval confirmed as purchase: ${item.description} ₹${item.totalValue}`, timestamp:now() });
      return prev;
    });
  };

  const returnToSupplier = (id) => {
    updateDB(prev=>{
      const item = (prev.approvalStock||[]).find(a=>a.id===id);
      if(!item) return prev;
      item.status = "returned";
      item.returnedAt = now();
      prev.auditLogs.push({ id:generateId(), action:"APPROVAL_RETURNED", entityId:id, details:`Approval returned: ${item.description} to ${item.partyName}`, timestamp:now() });
      return prev;
    });
  };

  const pending  = (db.approvalStock||[]).filter(a=>a.status==="pending");
  const resolved = (db.approvalStock||[]).filter(a=>a.status!=="pending");
  const pendingValue = pending.reduce((s,a)=>s+(a.totalValue||0),0);

  return (
    <div>
      {pending.length>0 && (
        <div style={{ padding:"10px 14px", background:"rgba(224,144,58,0.1)", border:"1px solid rgba(224,144,58,0.3)", borderRadius:"3px", marginBottom:"14px", fontSize:"12px", color:"#e0903a" }}>
          ⚠ Contingent Liability: <strong>₹{pendingValue.toLocaleString("en-IN",{maximumFractionDigits:0})}</strong> worth of goods on approval — not yet purchased or returned
        </div>
      )}
      <div style={{ display:"flex", gap:"8px", marginBottom:"14px" }}>
        <button className="btn btn-gold" style={{ marginLeft:"auto" }} onClick={()=>setShowForm(!showForm)}>+ Receive on Approval</button>
      </div>

      {showForm && (
        <div className="card card-gold fade-in" style={{ marginBottom:"14px" }}>
          <div className="modal-title">Receive Goods on Approval</div>
          <div className="info-box">Approval stock is a contingent liability — you are not committed to purchase until confirmed. No financial entry is created until you click "Confirm Purchase".</div>
          <div className="form-grid">
            <div className="form-group"><div className="label">Supplier *</div>
              <select value={form.partyId} onChange={e=>setForm({...form,partyId:e.target.value})}>
                <option value="">— Select Supplier —</option>
                {(db.parties||[]).filter(p=>p.type==="supplier"&&p.isActive).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="form-group"><div className="label">Category</div>
              <select value={form.category} onChange={e=>setForm({...form,category:e.target.value})}>
                <option value="gemstone">Gemstone / Diamond</option>
                <option value="pure_metal">Pure Metal</option>
                <option value="alloy">Alloy</option>
                <option value="jewellery">Finished Jewellery</option>
              </select>
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Description *</div>
              <input value={form.description} onChange={e=>setForm({...form,description:e.target.value})} placeholder="e.g. Assorted diamonds 0.3–0.5ct SI1" />
            </div>
            <div className="form-group"><div className="label">Quantity</div>
              <input type="number" step="0.001" value={form.quantity} onChange={e=>setForm({...form,quantity:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Unit</div>
              <select value={form.unit} onChange={e=>setForm({...form,unit:e.target.value})}>
                <option value="ct">Carats</option><option value="g">Grams</option><option value="pcs">Pieces</option>
              </select>
            </div>
            <div className="form-group"><div className="label">Rate per Unit (₹)</div>
              <input type="number" step="1" value={form.ratePerUnit} onChange={e=>setForm({...form,ratePerUnit:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Total Value (₹)</div>
              <input type="number" step="1" value={form.totalValue||(form.ratePerUnit&&form.quantity?(parseFloat(form.ratePerUnit)*parseFloat(form.quantity)).toFixed(0):"")} onChange={e=>setForm({...form,totalValue:e.target.value})} />
            </div>
            <div className="form-group"><div className="label">Date Received</div>
              <input type="date" value={form.receivedDate} onChange={e=>setForm({...form,receivedDate:e.target.value})} />
            </div>
            <div className="form-group" style={{ gridColumn:"1/-1" }}><div className="label">Notes</div>
              <input value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} />
            </div>
          </div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button className="btn btn-gold" onClick={handleAdd}>✓ Record Approval Receipt</button>
            <button className="btn" onClick={()=>setShowForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      {pending.length>0 && (
        <div className="card card-gold" style={{ marginBottom:"14px" }}>
          <div className="section-title" style={{ color:"#e0903a" }}>⏳ Pending Decision ({pending.length} items)</div>
          <table>
            <thead><tr><th>Date</th><th>Supplier</th><th>Description</th><th>Qty</th><th>Value</th><th>Action</th></tr></thead>
            <tbody>
              {pending.map(a=>(
                <tr key={a.id}>
                  <td style={{ fontSize:"10px", color:"var(--gold-dim)" }}>{new Date(a.receivedDate).toLocaleDateString("en-IN")}</td>
                  <td style={{ color:"var(--gold)", fontSize:"12px" }}>{a.partyName}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{a.description}</td>
                  <td style={{ fontSize:"12px" }}>{a.quantity} {a.unit}</td>
                  <td style={{ fontWeight:"bold", color:"#e0903a" }}>₹{(a.totalValue||0).toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                  <td>
                    <div style={{ display:"flex", gap:"6px" }}>
                      <button className="btn btn-sm btn-gold" onClick={()=>confirmPurchase(a.id)}>✓ Purchase</button>
                      <button className="btn btn-sm" style={{ color:"#d46060", borderColor:"#d46060" }} onClick={()=>returnToSupplier(a.id)}>↩ Return</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {resolved.length>0 && (
        <div className="card card-gold" style={{ marginBottom:"16px" }}>
          <div className="section-title"><span className="section-title-accent"></span>✓ Resolved Approval Items</div>
          <table>
            <thead><tr><th>Date</th><th>Supplier</th><th>Description</th><th>Qty</th><th>Value</th><th>Outcome</th></tr></thead>
            <tbody>
              {[...resolved].reverse().map(a=>(
                <tr key={a.id}>
                  <td style={{ fontSize:"10px", color:"var(--gold-dim)" }}>{new Date(a.receivedDate).toLocaleDateString("en-IN")}</td>
                  <td style={{ fontSize:"12px" }}>{a.partyName}</td>
                  <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{a.description}</td>
                  <td style={{ fontSize:"12px" }}>{a.quantity} {a.unit}</td>
                  <td style={{ fontSize:"12px" }}>₹{(a.totalValue||0).toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                  <td><span className={`badge ${a.status==="purchased"?"badge-green":"badge-red"}`}>{a.status==="purchased"?"Purchased":"Returned"}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      {pending.length===0 && resolved.length===0 && (
        <div className="card card-gold" style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"40px" }}>No approval stock items yet</div>
      )}
    </div>
  );
}

// ── Party Ledger ────────────────────────────────────────────────────────
function PartyLedgerView({ db, updateDB }) {
  const [selectedParty, setSelectedParty] = useState("");
  const [showPayment, setShowPayment] = useState(false);
  const [payForm, setPayForm] = useState({ amount:"", payMode:"cash", date:"", notes:"" });

  const party = (db.parties||[]).find(p=>p.id===selectedParty);
  const txns = (db.financialTxns||[]).filter(t=>t.partyId===selectedParty).sort((a,b)=>new Date(a.date)-new Date(b.date));

  const handlePayment = () => {
    if(!selectedParty) return;
    if(!payForm.amount||parseFloat(payForm.amount)<=0) return alert("Enter amount");
    const bal = partyBalance(selectedParty, db.financialTxns||[]);
    const isDebtor = bal > 0; // party owes us
    updateDB(prev=>{
      if(!prev.financialTxns) prev.financialTxns=[];
      prev.financialTxns.push({
        id:generateId(), partyId:selectedParty,
        txType: isDebtor ? "receipt" : "payment", // receipt = customer pays us, payment = we pay supplier
        description: isDebtor ? "Payment received" : "Payment made",
        amount:parseFloat(payForm.amount),
        payMode:payForm.payMode, date:payForm.date||now(), notes:payForm.notes,
      });
      prev.auditLogs.push({ id:generateId(), action:isDebtor?"PAYMENT_RECEIVED":"PAYMENT_MADE", entityId:selectedParty, details:`₹${payForm.amount} — ${party?.name}`, timestamp:now() });
      return prev;
    });
    setPayForm({ amount:"", payMode:"cash", date:"", notes:"" });
    setShowPayment(false);
  };

  // Running balance
  let running = 0;
  const txnsWithBalance = txns.map(t=>{
    if(t.txType==="sale")        running += t.amount||0;
    if(t.txType==="purchase")    running -= t.amount||0;
    if(t.txType==="receipt")     running -= t.amount||0;
    if(t.txType==="payment")     running += t.amount||0;
    if(t.txType==="debit_note")  running += t.amount||0;
    if(t.txType==="credit_note") running -= t.amount||0;
    return { ...t, runningBalance: running };
  });

  const currentBal = partyBalance(selectedParty, db.financialTxns||[]);

  return (
    <div>
      <div style={{ display:"flex", gap:"10px", marginBottom:"16px", alignItems:"center", flexWrap:"wrap" }}>
        <div className="form-group" style={{ marginBottom:0, minWidth:"220px" }}>
          <div className="label">Select Party</div>
          <select value={selectedParty} onChange={e=>setSelectedParty(e.target.value)}>
            <option value="">— Choose a party —</option>
            <optgroup label="Customers (Debtors)">
              {(db.parties||[]).filter(p=>p.type==="customer").map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
            </optgroup>
            <optgroup label="Suppliers (Creditors)">
              {(db.parties||[]).filter(p=>p.type==="supplier").map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
            </optgroup>
          </select>
        </div>
        {selectedParty && (
          <button className="btn btn-gold" style={{ alignSelf:"flex-end" }} onClick={()=>setShowPayment(!showPayment)}>
            {partyBalance(selectedParty, db.financialTxns||[])>0 ? "↓ Record Payment Received" : "↑ Record Payment Made"}
          </button>
        )}
      </div>

      {selectedParty && party && (
        <div>
          <div style={{ display:"flex", gap:"12px", marginBottom:"14px", flexWrap:"wrap" }}>
            <div style={{ padding:"10px 16px", background:"var(--dark3)", border:"1px solid var(--dark4)", borderRadius:"3px" }}>
              <div style={{ fontSize:"10px", color:"var(--gold-dim)", letterSpacing:"1px" }}>PARTY</div>
              <div style={{ fontSize:"14px", color:"var(--gold)", fontWeight:"bold", marginTop:"2px" }}>{party.name}</div>
              <div style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{party.type==="customer"?"Customer":"Supplier"} · {party.phone||""}</div>
            </div>
            <div style={{ padding:"10px 16px", background:"var(--dark3)", border:`1px solid ${currentBal===0?"var(--dark4)":currentBal>0?"#4db88a44":"#d4606044"}`, borderRadius:"3px" }}>
              <div style={{ fontSize:"10px", color:"var(--gold-dim)", letterSpacing:"1px" }}>CURRENT BALANCE</div>
              <div style={{ fontSize:"18px", fontWeight:"bold", color: currentBal===0?"var(--gold-dim)":currentBal>0?"#4db88a":"#d46060", marginTop:"2px" }}>
                ₹{Math.abs(currentBal).toLocaleString("en-IN",{maximumFractionDigits:0})}
              </div>
              <div style={{ fontSize:"11px", color:"var(--gold-dim)" }}>
                {currentBal===0?"Settled":currentBal>0?"They owe us":"We owe them"}
              </div>
            </div>
          </div>

          {showPayment && (
            <div className="card card-gold fade-in" style={{ marginBottom:"14px" }}>
              <div className="modal-title">{currentBal>0?"Record Payment Received":"Record Payment Made"}</div>
              <div className="form-grid">
                <div className="form-group"><div className="label">Amount (₹) *</div>
                  <input type="number" step="1" value={payForm.amount} onChange={e=>setPayForm({...payForm,amount:e.target.value})} />
                </div>
                <div className="form-group"><div className="label">Payment Mode</div>
                  <select value={payForm.payMode} onChange={e=>setPayForm({...payForm,payMode:e.target.value})}>
                    <option value="cash">Cash</option>
                    <option value="bank">Bank Transfer</option>
                    <option value="cheque">Cheque</option>
                    <option value="upi">UPI</option>
                  </select>
                </div>
                <div className="form-group"><div className="label">Date</div>
                  <input type="date" value={payForm.date} onChange={e=>setPayForm({...payForm,date:e.target.value})} />
                </div>
                <div className="form-group"><div className="label">Notes / Reference</div>
                  <input value={payForm.notes} onChange={e=>setPayForm({...payForm,notes:e.target.value})} placeholder="Cheque no, UTR, etc." />
                </div>
              </div>
              <div style={{ display:"flex", gap:"8px" }}>
                <button className="btn btn-gold" onClick={handlePayment}>✓ Record Payment</button>
                <button className="btn" onClick={()=>setShowPayment(false)}>Cancel</button>
              </div>
            </div>
          )}

          <div className="card card-gold">
            <div className="section-title"><span className="section-title-accent"></span>Account Statement — {party.name}</div>
            {txnsWithBalance.length===0 && <div style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No transactions yet for this party.</div>}
            {txnsWithBalance.length>0 && (
              <table>
                <thead><tr><th>Date</th><th>Type</th><th>Description</th><th>Debit (Dr)</th><th>Credit (Cr)</th><th>Balance</th><th>Mode</th></tr></thead>
                <tbody>
                  {txnsWithBalance.map(t=>{
                    const isDebit  = ["sale","payment","debit_note"].includes(t.txType);
                    const isCredit = ["purchase","receipt","credit_note"].includes(t.txType);
                    return (
                      <tr key={t.id}>
                        <td style={{ fontSize:"10px", color:"var(--gold-dim)", whiteSpace:"nowrap" }}>{new Date(t.date).toLocaleDateString("en-IN")}</td>
                        <td><span className={`badge ${t.txType==="sale"?"badge-green":t.txType==="purchase"?"badge-red":t.txType==="receipt"?"badge-gold":"badge-blue"}`} style={{ fontSize:"9px" }}>{t.txType.replace("_"," ").toUpperCase()}</span></td>
                        <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{t.description||"—"}</td>
                        <td style={{ color:"#d46060", fontWeight:isDebit?"bold":"normal" }}>{isDebit?`₹${(t.amount||0).toLocaleString("en-IN",{maximumFractionDigits:0})}`:"—"}</td>
                        <td style={{ color:"#4db88a", fontWeight:isCredit?"bold":"normal" }}>{isCredit?`₹${(t.amount||0).toLocaleString("en-IN",{maximumFractionDigits:0})}`:"—"}</td>
                        <td style={{ fontWeight:"bold", color:t.runningBalance>0?"#4db88a":t.runningBalance<0?"#d46060":"var(--gold-dim)" }}>
                          {t.runningBalance===0?"—":`₹${Math.abs(t.runningBalance).toLocaleString("en-IN",{maximumFractionDigits:0})} ${t.runningBalance>0?"Dr":"Cr"}`}
                        </td>
                        <td style={{ fontSize:"10px" }}>{t.payMode||"—"}</td>
                      </tr>
                    );
                  })}
                  <tr style={{ borderTop:"2px solid var(--gold-dim)", background:"var(--dark3)", fontWeight:"bold" }}>
                    <td colSpan={3} style={{ color:"var(--gold)", fontSize:"12px" }}>CLOSING BALANCE</td>
                    <td colSpan={2}></td>
                    <td style={{ color:currentBal>0?"#4db88a":currentBal<0?"#d46060":"var(--gold-dim)", fontSize:"13px" }}>
                      {currentBal===0?"Settled":`₹${Math.abs(currentBal).toLocaleString("en-IN",{maximumFractionDigits:0})} ${currentBal>0?"Dr":"Cr"}`}
                    </td>
                    <td></td>
                  </tr>
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}
      {!selectedParty && (
        <div className="card card-gold" style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"40px" }}>Select a party above to view their account statement</div>
      )}
    </div>
  );
}

// ── Outstanding ─────────────────────────────────────────────────────────
function OutstandingView({ db }) {
  const [view, setView] = useState("receivable");

  const customers  = (db.parties||[]).filter(p=>p.type==="customer"&&p.isActive);
  const suppliers  = (db.parties||[]).filter(p=>p.type==="supplier"&&p.isActive);
  const ftxns      = db.financialTxns||[];

  // Aging: days since oldest unpaid transaction
  const getAging = (partyId) => {
    const partyTxns = ftxns.filter(t=>t.partyId===partyId).sort((a,b)=>new Date(a.date)-new Date(b.date));
    if(partyTxns.length===0) return 0;
    const oldest = partyTxns[0].date;
    return Math.floor((Date.now()-new Date(oldest))/(1000*60*60*24));
  };

  const debtors   = customers.map(p=>({ ...p, balance:partyBalance(p.id,ftxns), aging:getAging(p.id) })).filter(p=>p.balance>0).sort((a,b)=>b.balance-a.balance);
  const creditors = suppliers.map(p=>({ ...p, balance:partyBalance(p.id,ftxns), aging:getAging(p.id) })).filter(p=>p.balance<0).sort((a,b)=>a.balance-b.balance);

  const totalReceivable = debtors.reduce((s,p)=>s+p.balance,0);
  const totalPayable    = creditors.reduce((s,p)=>s+Math.abs(p.balance),0);

  const agingBucket = (days) => {
    if(days<=30)  return { label:"0–30 days", color:"#4db88a" };
    if(days<=60)  return { label:"31–60 days", color:"#c8a850" };
    if(days<=90)  return { label:"61–90 days", color:"#e0903a" };
    return              { label:"90+ days",  color:"#d46060" };
  };

  const list = view==="receivable" ? debtors : creditors.map(p=>({...p, balance:Math.abs(p.balance)}));

  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"12px", marginBottom:"16px" }}>
        <div className="stat-card highlight" style={{ cursor:"pointer", border:view==="receivable"?"1px solid var(--gold)":"1px solid var(--dark4)" }} onClick={()=>setView("receivable")}>
          <div className="label">Total Receivable</div>
          <div className="value" style={{ color:"#4db88a", fontSize:"18px" }}>₹{totalReceivable.toLocaleString("en-IN",{maximumFractionDigits:0})}</div>
          <div style={{ fontSize:"11px", color:"var(--gold-dim)", marginTop:"4px" }}>{debtors.length} customers owe us</div>
        </div>
        <div className="stat-card highlight" style={{ cursor:"pointer", border:view==="payable"?"1px solid var(--gold)":"1px solid var(--dark4)" }} onClick={()=>setView("payable")}>
          <div className="label">Total Payable</div>
          <div className="value" style={{ color:"#d46060", fontSize:"18px" }}>₹{totalPayable.toLocaleString("en-IN",{maximumFractionDigits:0})}</div>
          <div style={{ fontSize:"11px", color:"var(--gold-dim)", marginTop:"4px" }}>{creditors.length} suppliers we owe</div>
        </div>
      </div>

      <div className="card card-gold">
        <div className="section-title"><span className="section-title-accent"></span>{view==="receivable"?"Receivables — Customers Owe Us":"Payables — We Owe Suppliers"}</div>
        {list.length===0 && <div style={{ textAlign:"center", color:"var(--text-dim)", fontSize:"11px", letterSpacing:"1.5px", padding:"28px 12px" }}>No outstanding {view==="receivable"?"receivables":"payables"}</div>}
        {list.length>0 && (
          <table>
            <thead><tr><th>Party</th><th>Contact</th><th>Amount</th><th>Aging</th><th>Bucket</th></tr></thead>
            <tbody>
              {list.map(p=>{
                const ag = agingBucket(p.aging);
                return (
                  <tr key={p.id}>
                    <td style={{ color:"var(--gold)", fontWeight:"bold" }}>{p.name}</td>
                    <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{p.phone||"—"}</td>
                    <td style={{ fontWeight:"bold", color:view==="receivable"?"#4db88a":"#d46060", fontSize:"14px" }}>₹{p.balance.toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                    <td style={{ fontSize:"11px", color:"var(--gold-dim)" }}>{p.aging} days</td>
                    <td><span style={{ background:ag.color+"22", color:ag.color, padding:"2px 8px", borderRadius:"2px", fontSize:"11px", fontWeight:"bold" }}>{ag.label}</span></td>
                  </tr>
                );
              })}
              <tr style={{ borderTop:"2px solid var(--gold-dim)", background:"var(--dark3)", fontWeight:"bold" }}>
                <td style={{ color:"var(--gold)" }}>TOTAL</td>
                <td></td>
                <td style={{ color:view==="receivable"?"#4db88a":"#d46060", fontSize:"14px" }}>₹{list.reduce((s,p)=>s+p.balance,0).toLocaleString("en-IN",{maximumFractionDigits:0})}</td>
                <td colSpan={2}></td>
              </tr>
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}



